// fbm-displaced drift
fn render(c : Ctx) -> vec3f {
  let t = c.rawT * c.speed;
  let q = c.uv + vec2f(fbm(c.uv * 3.0 + t * 0.3) - 0.5, fbm(c.uv * 3.0 - t * 0.25) - 0.5)
              * (0.02 + c.bass * 0.05 + c.beat * 0.03);
  var col = srcTex(q);
  col = max(col, prevTex(q + vec2f(0.0, 0.002)) * c.fb);
  return col;
}
